"""
MKT Context Commentary — Job chapters 36–38
Run: python3 scripts/zc-context-job-36-38.py
Verses: ch36×33 + ch37×24 + ch38×41 = 98

Key notes:
- ch36: Elihu's closing theological argument — God as incomparable teacher who
  instructs through affliction. vv27-33 introduce the meteorological motif that will
  dominate ch37 and frame the divine speech in ch38.
- ch37: Elihu's storm-theophany peroration — the tempest as divine self-disclosure.
  The chapter functions as the literary hinge between Elihu's human wisdom and YHWH's
  direct speech. v9's 'whirlwind from the south' (sûp̄āh) anticipates ch38:1's
  'whirlwind' (sĕʿārāh) from which God answers.
- ch38: The divine speech — YHWH answers from the whirlwind with a series of
  rhetorical cosmogonic questions. This is the first YHWH occurrence since the prose
  frame (chs. 1-2); within the poetic dialogue only ʾĔlōah/Šaddai/ʾĒl were used.
  The return of the divine name marks the theological breakthrough. The chapter does
  not answer Job's complaints but reframes the entire enterprise.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB3638 = {
  "36": {
    "1": "<p>'Elihu continued and said' — Elihu's fourth speech begins with the same wayyōsep̄ resumptive marker as ch36:1 MT. This is his final extended argument, concluding with the meteorological hymn that will transition into YHWH's own whirlwind speech. Structurally, Elihu functions as both foil to the three friends (he arrives fresh after their failure) and as theological preparation for the divine answer. His speeches (chs. 32-37) are widely regarded as a later addition to the core dialogue, but their literary placement is deliberate: they intensify the theophanic tension.</p>",
    "2": "<p>'Bear with me a little longer (ṣĕʿar)' — the patience-request echoes the wisdom teacher's address to pupils who must wait for understanding to be complete. Elihu presents himself as God's advocate (v3: 'I will ascribe righteousness to my Maker'), a role that distinguishes him from the three friends who attempted to defend God by condemning Job. His claim that he 'still has something to say in God's defense' frames his speech as amicus curiae testimony in the divine court — the book's legal metaphor extends through his peroration.</p>",
    "3": "<p>'I will draw my knowledge from a wide range (lĕmērāḥôq)' — from far away/afar; the image is of gathering knowledge from distant sources, perhaps implying cosmological or universal scope in contrast to the friends' limited retributive framework. 'Ascribe righteousness to my Maker' — this phrase anticipates Job's own eventual response in 40:8 where God challenges Job: 'Will you condemn me that you may be righteous?' Elihu already proposes what the divine speech will vindicate: that God's governance is righteous and can be seen as such from a sufficiently wide perspective.</p>",
    "4": "<p>'For truly my words are not false; one complete in knowledge (tĕmîm dēʿôṯ) stands before you' — tāmîm (complete/blameless) applied to knowledge is unique here; elsewhere tāmîm describes moral integrity (Gen 6:9 Noah; 17:1 Abraham; Ps 15:2). Elihu's claim to be 'complete in knowledge' is a bold claim that many readers find arrogant — yet the divine speech partially vindicates Elihu in that it does not rebuke him (38:1 addresses Job directly; 42:7-9 rebukes only the three friends, not Elihu). Whether this constitutes validation of Elihu's claim is debated.</p>",
    "5": "<p>'Behold, God is mighty (ḵabbîr) and despises no one' — ḵabbîr (mighty/great; from kābar, to be great/heavy) appears here and in v26 ('God is great, beyond knowing') framing the Elihu speech with divine greatness. The claim that God 'despises no one' (wĕlōʾ yimʾas) directly contradicts what Job has perceived: that God has rejected/despised him (9:21; 30:22). Elihu is arguing that God's might is never arbitrary contempt but always purposeful governance. The Psalter uses the same term for the God who does not despise the afflicted (Ps 22:24).</p>",
    "6": "<p>'He does not keep the wicked alive, but gives justice (mišpāṭ) to the poor (ʿăniyyîm)' — the distributive justice schema: the wicked die; the poor receive legal protection. This is the classic Deuteronomic framework (Deut 10:18 'he executes justice for the fatherless and the widow') and the Psalter's repeated claim (Ps 10:14-18; 146:7-9). Elihu is asserting that God's pattern, rightly understood, favors the vulnerable — which is meant to comfort Job but inadvertently classifies him as either wicked (dying) or not-yet-vindicated poor.</p>",
    "7": "<p>'He does not take his eyes off the righteous (ṣaddîqîm); he seats them on the throne with kings and exalts them forever' — the double honor: divine surveillance (protective watching, not punitive scrutiny) and social elevation to royal dignity. The irony is that Job began in exactly this position (the divine attention of 1:8 'Have you considered my servant Job?') and now experiences it as catastrophic. Elihu is citing the theological principle; Job is living the theological exception that the principle cannot account for. The 'forever' (lāneṣaḥ) of their exaltation anticipates the restoration of ch42.</p>",
    "8": "<p>'And if they are bound in chains (bakkabbullîm), caught in ropes of affliction (ḥablê ʿōnî)' — the transition from honor (v7) to affliction signals Elihu's pastoral intent: even the righteous may be temporarily bound. The binding imagery appears throughout the Psalms of individual lament (Ps 116:3 'cords of death entangled me'; 118:27 'bind the festival sacrifice with cords'). The chains (kabbul/kabbal) are literally 'fetters' — the metaphor is of divine discipline that temporarily restrains movement, not permanent condemnation.</p>",
    "9": "<p>'Then he shows them what they have done and their transgressions — that they have acted arrogantly' — the purpose of the binding is pedagogical revelation: God exposes to the sufferer what motivated divine action. The word for 'acted arrogantly' (yitgabbārû, hitpa'el of gābar) is the same root used for a warrior's strength; here it means self-willed excess. Elihu's framework: suffering is God's tutorial that identifies specific behavioral patterns in the sufferer that need correction. This is Hebrews 12:5-11's 'discipline' (paideia) theology, which cites Prov 3:11-12 (itself drawing on this tradition).</p>",
    "10": "<p>'He opens their ears (gilāh ʾāzĕnām) to correction' — gilāh ʾōzen (uncover/open the ear) is a prophetic revelation formula: 1 Sam 9:15 (YHWH reveals to Samuel); 2 Sam 7:27 (YHWH uncovers David's ear about the temple promise); Isa 50:4-5 (the Servant's ear opened by God each morning for instruction). Its use here by Elihu is significant: the instrument of divine communication is the ear-opening, not the thunderbolt or the voice in the whirlwind — though ch38 will deploy that form too. The pedagogical opening precedes the storm disclosure.</p>",
    "11": "<p>'If they listen and serve him, they will complete their days in prosperity (bĕṭôḇ) and their years in comfort (binnĕʿîmîm)' — the condition-consequence structure of the Wisdom tradition's two-ways framework: Prov 3:1-2 ('do not forget my law... so your days will be many and prosperous'); Deut 28:1-14 (the blessings for obedience). The temporal completeness ('complete their days') echoes the life-completion formula for the patriarchs (Gen 25:8; 35:29 'full of years'). Elihu is not wrong about the general pattern — he is wrong to apply it as a simple diagnostic to Job's specific case.</p>",
    "12": "<p>'But if they do not listen, they will perish by the sword (šelaḥ, = javelin/spear) and die without ever understanding (lĕḇaltî-ḏāʿaṯ)' — the two-ways formula completes: the path of refusal ends in violent death and intellectual darkness. lĕḇaltî-ḏāʿaṯ (without knowledge/understanding) is the opposite of the wisdom goal; Prov 5:23 'he dies for lack of discipline and is lost through his great folly.' The specific judgment instrument (sword/weapon) connects to the covenant curse vocabulary of Leviticus 26:25 and Deuteronomy 28:22.</p>",
    "13": "<p>'The godless in heart (ḥanĕpê-lēḇ) store up resentment (śāmû ʾāp̄)' — ḥānēp̄ (godless/profane, one who is impious without necessarily being an external apostate) stores anger rather than submitting in affliction. The phrase śāmû ʾāp̄ (they place/store anger) is unique — the wicked nurture their resentment against God's correction instead of repenting. 'They do not cry to God when he binds them' — the failure of prayer as the marker of godlessness: the righteous cry to God even in extremity (Ps 22:24; 34:15-18) while the godless maintain their self-sufficiency to the end.</p>",
    "14": "<p>'They die young (bĕnaʿar), and their life ends among the cult prostitutes (qĕḏēšîm)' — the qĕḏēšîm (cult prostitutes, literally 'consecrated ones'; masculine form) appear in Deuteronomy 23:17-18 ('no Israelite man shall be a qāḏēš'), 1 Kings 14:24, and 15:12 (Josiah purging them from the land). The association of premature death with this category represents moral and cultic pollution — the ultimate social disgrace in the Deuteronomic framework. The verse is stark: the godless die young and die in shame.</p>",
    "15": "<p>'But he rescues (ḥālaq, or better yĕḥallēṣ = delivers) the afflicted through their suffering (ʿōnî) and opens their ears through oppression (lĕlaḥaṣ)' — the counter-trajectory: for the humble, the very suffering that would destroy the godless becomes the instrument of salvation. The verb ḥālaṣ (to draw out/deliver/pull free) appears in the Exodus vocabulary (Ps 81:6) and in the individual rescue psalms (Ps 34:7 'angel of the LORD encamps around those who fear him and delivers them'). Elihu's theological point here is close to Isaiah 53:4-5 (through his suffering he bore their afflictions).</p>",
    "16": "<p>'Indeed, he was drawing you from the jaws of distress (ḥāṣar ṣār) into a broad place (rĕḥāḇāh)' — the 'broad place' (rĕḥāḇāh, spaciousness/freedom from constraint) is the standard Psalms-vocabulary for divine rescue from distress: Ps 18:19 'he brought me out into a broad place'; Ps 31:8; 118:5 'out of my distress (min-hammēṣar) I called on the LORD; he answered and set me in a broad place (bammerḥāḇ).' Elihu is applying to Job the Psalms of rescue in the present tense — insisting that the rescue process is underway, not that Job has been abandoned.</p>",
    "17": "<p>'But now you are full of the judgment due the wicked; judgment and justice have seized you' — Elihu's sharp pivot: Job's current situation appears to fulfill the formula for wickedness. The observation is empirically accurate (Job suffers) but theologically misapplied (Job is not wicked). The verse exposes the structural problem of retributive theology: it reads providential patterns backwards from outcomes — seeing suffering and concluding guilt. The book's resolution in ch42 will reverse this reading entirely, vindicating Job precisely as a righteous sufferer.</p>",
    "18": "<p>'Beware that anger (śĕḥōq, = mockery/laughing) does not lead you into scoffing' — the warning against turning from patient endurance to bitter mockery of God. The fear that suffering, when it does not resolve into the expected pattern, will produce theological cynicism — the 'scoffers' (lēṣîm) of Proverbs who mock the wisdom framework itself (Prov 1:22; 3:34; 19:29). 'Do not let the greatness of the required payment (ḵōp̄er, ransom) turn you away' — ḵōp̄er (ransom/redemption price) here refers to the scale of what Job perceives is owed; the ransom metaphor connects to the redemption vocabulary of Exodus.</p>",
    "19": "<p>'Will your wealth (šûʿăṯĕḵā, = outcry/riches) hold you in distress?' — the ironic question: all that Job once possessed (the great wealth of ch1) cannot maintain him now, cannot purchase the outcome he desires. The wisdom tradition consistently warns against trusting in wealth as a buffer against divine judgment: Prov 11:4 'wealth does not profit in the day of wrath'; 11:28 'whoever trusts in riches will fall.' Job has already made this point himself — his wealth is gone and proved unable to save him.</p>",
    "20": "<p>'Do not long for the night (lĕlayyĕlāh) when people vanish from where they stand' — the 'night' here may refer to death (a common metaphor: Ps 30:5 'weeping stays for the night'; John 9:4 'night comes when no one can work') or to the chaotic darkness before divine intervention. The warning against wishing for death is a pastoral note: Job has explicitly desired death throughout (3:3-13; 6:8-9; 14:13). Elihu warns that this longing itself is spiritually dangerous — a turning from God rather than toward him.</p>",
    "21": "<p>'Be careful not to turn toward evil, for this is what you have been choosing over enduring affliction' — the accusation that Job's theological challenges to God are themselves a choice of evil over patient suffering. This is the most pointed of Elihu's charges and the most debatable: the book's prologue has already established Job's integrity, and God's eventual speech does not vindicate Elihu's specific accusation against Job. However, the general principle — that impatient protest can shade into genuine rebellion — is a real spiritual danger the text takes seriously.</p>",
    "22": "<p>'Behold, God is exalted in his power; who is a teacher (môreh) like him?' — môreh (teacher) is a rare divine epithet; it appears as a proper title only here and in Isa 30:20 ('your Teacher will no longer hide himself; your eyes will see your Teacher'). Isaiah 30:20's placement in a restoration oracle suggests that YHWH's role as direct Teacher of his people is an eschatological expectation — the age when the prophetic mediator is no longer needed because God himself teaches. Jesus's reception as teacher (rabbi) and the Spirit's role as the teaching Paraclete (John 14:26) fill this office in the NT.</p>",
    "23": "<p>'Who has prescribed (p̄āqad) his path for him? Who can say, You have done wrong?' — p̄āqad (to assign/commission/appoint) used here as prescribing God's route: no one can direct the divine governance. The question recurs in Isaiah 40:13 ('Who has directed the Spirit of the LORD or instructed him as his counselor?') — Paul quotes Isaiah 40:13 in Romans 11:34 and 1 Corinthians 2:16. The logic of both Isaiah and Elihu is the same: divine incomprehensibility implies that God cannot be called to account by the creature. Paul draws the further conclusion: that incomprehensibility is itself gracious news (Rom 11:33-36).</p>",
    "24": "<p>'Remember to extol his work, which people have sung about through the ages' — the command to praise as the appropriate human response to divine incomprehensibility. The hymnic tradition (mĕšōrĕrîm = those who sing/hymn) represents the accumulated human witness to God's works across generations: the Psalter itself is this tradition. The call to 'remember' (zĕḵar) and 'extol' (śĕgāʾ) connects to the Psalms of orientation that celebrate divine works: Ps 77:11 'I will remember the deeds of the LORD'; Ps 111:2 'great are the works of the LORD; they are pondered by all who delight in them.'</p>",
    "25": "<p>'All people have seen it (ḥāzāh); everyone looks at it (yāḇîṭ) from a distance' — the universal accessibility of the divine work in creation as a theological premise: every human being has some capacity to perceive what God does in the world. This is the premise of natural theology (Rom 1:19-20 'since the creation of the world, God's invisible qualities... have been clearly seen'). The 'from a distance' (mērāḥôq) may acknowledge the epistemic limit: created beings can see the works but not comprehend the Worker — the same limit that Job's cosmological questions have approached.</p>",
    "26": "<p>'Behold, God is great, beyond our knowing (lōʾ-nēḏāʿ); the number of his years cannot be counted' — lōʾ-nēḏāʿ is a remarkable predicate: God is incomprehensible. The claim that divine years 'cannot be counted' (wĕlōʾ yēḥqer) uses the same root (ḥāqar) as Job's accusation in 5:27 ('we have searched this out; it is true'); now applied to divine eternity itself as beyond searching. The year-metaphor connects to Ps 90:2 ('from everlasting to everlasting, you are God') and Rev 1:8 ('the Alpha and Omega... who is and was and is to come'). Paul's doxology in 1 Tim 6:16 ('unapproachable light... no one has seen or can see') draws on this tradition.</p>",
    "27": "<p>'For he draws up the drops of water (yigra ʿnṭpê-māyim); they distill as rain from the mist' — the meteorological cycle described: YHWH draws up moisture from the surface waters (evaporation), which condenses and falls as rain. The physical accuracy of the description is notable: the Hebrew verb gāraʿ (to diminish/draw off) captures the drawing-away of moisture from surfaces. This is an early articulation of the hydrological cycle — not as scientific observation but as a theological claim: even the invisible mechanics of weather are divine governance.</p>",
    "28": "<p>'Which the clouds pour down (yizzĕlû) and drop on people in abundance' — the cascade from vapor to cloud to rain as a series of divine actions, each step a new distributive act. The theological point is that rain is not a natural process operating independently but a continuous divine provision: Deut 11:14 ('I will send rain on your land in its season'); Matt 5:45 ('he sends rain on the righteous and unrighteous'). The word nāzal (to flow/trickle down) is the same used in Isa 45:8 for righteousness 'showering down from the clouds' — meteorological and ethical provisions in one image.</p>",
    "29": "<p>'Can anyone understand the spreading of the clouds (mip̄rĕśê ʿāḇ) or the thunder from his canopy (śûkkāh)?' — the rhetorical question form that will dominate ch38 appears here in Elihu's speech as a preview. śukkāh (canopy/booth/tent) is the sacred tent vocabulary: the divine 'booth' as the protective overhead structure from which thunder comes. The same root covers the Sukkot booths of Lev 23:42 and the 'shelter' of Ps 27:5 ('he will hide me in his sukkah'). God's meteorological dwelling is structurally analogous to his covenantal dwelling-place.</p>",
    "30": "<p>'See, he scatters his lightning (bĕrāqāyw) around him and covers the depths of the sea' — the global scope of lightning as divine communication: it is not random but 'scattered' (p̄ārāś) from the divine center outward in every direction. The 'covering the depths of the sea' clause (wĕšārĕšê hayyām ḵissāh) is difficult; it may describe how lightning illuminates to the ocean's roots, revealing what is normally hidden. This cosmic lightning imagery appears in Ps 77:18 (theophanic psalm: 'your lightnings lit up the world; the earth trembled and quaked') and Ps 97:4 ('his lightning lit up the world').</p>",
    "31": "<p>'For by these (bām = by/with them) he governs peoples and provides food in abundance' — the political and agricultural dual function of storms: the same meteorological power that destroys (judgment on nations) provides sustenance (rain for crops). The connection between rain and governance appears throughout the OT: Deut 28:23-24 (no rain as covenant curse); 1 Kings 17-18 (Elijah's drought as prophetic sign against Ahab); Jer 5:24 ('they do not say in their hearts, Let us fear the LORD our God, who gives the autumn and spring rains'). The nations are governed by the same mechanism that feeds them.</p>",
    "32": "<p>'He covers his hands with lightning (ʿal-kappayim kissāh ʾôr) and commands it to strike its mark (wayĕṣawwehû ʿal-maprîaʿ)' — the image of God wielding lightning as a weapon held in covered hands that are revealed at the moment of striking is a remarkable anthropomorphism. The divine hands (kappayim) appear throughout the Psalter as agents of salvation (Ps 16:11; 31:5 'into your hand I commit my spirit') and judgment (Ps 76:5). Lightning as a divine arrow is explicit in Ps 18:14 ('he shot his arrows and scattered them; great bolts of lightning and routed them').</p>",
    "33": "<p>'Its thunder (raʿm) announces his presence (miqneh = regarding what is coming); the cattle also sense the coming storm' — the verse functions as the final note of ch36's meteorological hymn: even the cattle register the approach of the divine storm, their instinctual response being a form of creaturely acknowledgment. The juxtaposition of human argument (vv2-21) and animal instinct (v33) sets up the contrast that YHWH will exploit in ch38-39: the animals 'know' God's ordering by instinct while Job's sophisticated theological arguments miss what the creatures grasp.</p>"
  },
  "37": {
    "1": "<p>'At this my heart trembles (yehĕrad libbî) and leaps from its place' — Elihu's personal response to the theophanic signs he is describing. The verb ḥāraḏ (to tremble/quake with awe) is the standard theophanic-approach response: Exod 19:16 (people trembled at Sinai); 1 Sam 4:13 (Eli trembles at bad news); Isa 66:2 ('to this one I will look: to him who is humble and contrite in spirit, who trembles [ḥāreḏ] at my word'). The heart leaping out of its place is a more extreme image — the internal organ of discernment is destabilized by divine approach.</p>",
    "2": "<p>'Listen carefully (šimʿû šāmôaʿ) to the roar of his voice (bĕrōgez qōlô) and the rumble that goes out from his mouth' — the double imperative (infinitive absolute + finite verb = intensive command) focuses attention on the divine voice. rōgez (normally 'agitation/anger') here describes the thunderous quality of the divine voice — not wrathful anger but the disturbing power of the sound. The double auditory reference (voice/qōl + rumble going forth) parallels Ps 29's 'voice of the LORD' (qôl-YHWH) thunderstorm poem, which uses the same term seven times.</p>",
    "3": "<p>'He sends it (lightning) under the whole sky (taḥat kol-haššāmayim) and his lightning (ʾôrô) to the ends of the earth' — the global scope of divine lightning establishes that what Elihu describes is not a local weather event but a theophanic sign addressed to the whole earth. The 'ends of the earth' (ḵanp̄ôṯ hāʾāreṣ = the wings/extremities of the land) appears in Isaiah 40:28; 41:5,9; 43:6 as the reaches of YHWH's sovereign domain. The same formula in Ps 97:4 follows theophanic lightning language: 'his lightnings lit up the world; the earth saw and trembled.'</p>",
    "4": "<p>'After the lightning a voice roars (yiṣʿaq); he thunders (yarʿēm) in his majestic voice (bĕqôl gĕʾônô)' — the sequential meteorological theology: lightning precedes thunder (as observed), but in theological terms the voice (thunder) is the meaningful communication while the lightning is the sign that precedes it. gĕʾôn (majesty/pride) when applied to God is positive transcendence: Ps 68:34 'his majesty is over Israel and his power in the clouds.' 'He does not hold the lightnings back once his voice sounds' — the completeness of divine disclosure: once God speaks, the full arsenal of theophanic signs follows without restraint.</p>",
    "5": "<p>'God thunders astoundingly (p̄elāʾôṯ) with his voice' — p̄eleʾ (wonder/marvel) as a divine attribute: Ps 77:11 'I will remember your wonders (p̄ilĕʾôṯeyḵā)'; Isa 9:6 (the Messianic title 'Wonderful Counselor', p̄eleh yôʿēṣ). 'He does great things beyond our understanding (wĕlōʾ nēḏāʿ)' — the same lōʾ-nēḏāʿ incomprehensibility predicate from 36:26 reappears: the theme of divine incomprehensibility brackets Elihu's meteorological hymn (36:26; 37:5). This double framing prepares for YHWH's own incomprehensibility questions in ch38.</p>",
    "6": "<p>'For he says to the snow: Fall upon the earth' — the divine command (ʾāmar = he says) to snow as a personal instruction illustrates that natural phenomena are not impersonal forces but responsive servants of the divine word. This personalizes the cosmological relationship: the Psalmist makes the same point in Ps 148:7-8 ('praise the LORD from the earth... snow and clouds, stormy wind fulfilling his word'). The parallel to Gen 1 is deliberate: there too God speaks and natural phenomena come into existence or behavior.</p>",
    "7": "<p>'He seals (ḥātam) the hand of every person (bĕyaḏ-kol-ʾāḏām) so that all humanity may perceive (lāḏaʿaṯ) his work' — ḥātam (to seal/mark) the human hand: this is difficult, and interpretations divide. Most likely: during winter storms, fieldwork is impossible ('sealed off') so human beings are forced to stop their activity and observe the divine works. The theophanic storm functions pedagogically — it creates the attentional space for perceiving God's activity. An alternative reading sees the seal as a marking/signing, analogous to Job's own legal 'signature' in 31:35 (tāw = Job's mark).</p>",
    "8": "<p>'Then the wild animals go into their dens and stay in their lairs' — the animal response to the divine storm: ordered retreat to shelter rather than chaos. This image of instinctual creaturely response to weather will be picked up in ch38-39's survey of wild animals, where YHWH points to animal behavior as evidence of providential governance beyond human comprehension or control. The animals know their place in the divine order; the implicit critique of Job is that he does not similarly recognize his.</p>",
    "9": "<p>'From the south (mĕḥēḏer, = inner room/chamber) comes the whirlwind (sûp̄āh)' — the 'chamber' of the south where the whirlwind originates. sûp̄āh (whirlwind/storm) here anticipates the divine answer in 38:1 from sĕʿārāh (whirlwind/storm). Both terms describe the theophanic storm; Elihu's meteorological hymn approaches the same storm form that YHWH will actually speak from. 'And from the north comes the cold (qārāh)' — the two directional extremes (south whirlwind, north cold) frame the complete meteorological range under divine governance.</p>",
    "10": "<p>'By the breath of God (mĕnišmaṯ-ʾēl) ice is formed and the wide waters are frozen solid' — nišmaṯ-ʾēl (breath of God) echoes the creation vocabulary of Gen 2:7 (nišmaṯ ḥayyîm = breath of life) and Job 32:8 (Elihu's own earlier claim that 'the breath of the Almighty gives understanding'). Here the divine breath is meteorological rather than animating — it freezes rather than vivifies. The double use of nišmāh suggests Elihu sees continuity between the creation breath and the ongoing meteorological activity: both are expressions of the same divine respiratory action.</p>",
    "11": "<p>'He loads the clouds with moisture (bĕrî yāṭrîaḥ ʿāḇ) and scatters his lightning-cloud' — the clouds as weighted vessels that God fills and deploys. The physics are accurate: clouds are literally 'loaded' with water. Theologically, the meteorological process is a divine logistics operation: collection, loading, transport, and deployment of water resources. The image of God 'scattering' (yāp̄îṣ) the lightning cloud connects to the Psalms' imagery of divine arrows scattered against the enemy (Ps 18:14; 144:6).</p>",
    "12": "<p>'It turns in every direction by his guidance (bĕtaḥbûlōṯāyw), to do whatever he commands across the face of the inhabited earth' — taḥbûlāh (guidance/steersmanship; from ḥeḇel = rope, specifically a ship's steering rope). The metaphor is nautical: God is the helmsman of meteorological phenomena. The word appears in Prov 1:5; 11:14; 12:5; 20:18; 24:6 for the skilled navigation of human affairs (military strategy, wise counsel). By using ship-steering vocabulary for weather governance, Elihu frames divine providence as expert navigational skill rather than arbitrary force.</p>",
    "13": "<p>'He brings it whether as discipline (lĕšēbeṭ), for his land's sake (lĕʾarṣô), or as steadfast love (lĕḥeseḏ)' — this tripartite purpose for storms is unique to Elihu and theologically significant: the same meteorological event serves three potentially different divine intentions depending on who receives it. šēbeṭ (rod/staff/discipline) is the discipline of Prov 13:24 ('he who hates his son spares the rod') and Heb 12:5-11; lĕʾarṣô (for his land) is providential care for creation's welfare; ḥeseḏ (steadfast covenant love) signals that weather itself can be an expression of covenantal grace.</p>",
    "14": "<p>'Listen to this, Job; stop (ʿămōḏ = stand still) and consider (hiṯbônān) the wondrous works of God' — the direct address to Job after the impersonal meteorological description. The imperative to stand still recalls Moses at the burning bush (Exod 3:5 'take off your sandals') and Israel at the sea (Exod 14:13 'Stand firm and see the salvation of the LORD'). hiṯbônān (hitpa'el of bîn = to discern/understand) is intensive reflection: not passive observation but active contemplation. The wondrous works (nip̄lĕʾôṯ ʾēl) echo the Exodus miracles of Ps 78:4 and connect to Isa 28:29 ('his works are wonderful; his counsel is magnificent').</p>",
    "15": "<p>'Do you know how God arranged (śîm) these things and caused the lightning in his cloud to flash?' — the first rhetorical question preparing the mode of ch38's cosmogonic interrogation. śîm (to set/arrange/place) is the creator's organizing action: God arranges the meteorological elements. The lightning 'flashing' (hôpîaʿ, from yāp̄aʿ = to shine out) is the same term used for divine epiphany in Ps 80:1 ('you who sit enthroned between the cherubim, shine forth') and 94:1 ('God... shine forth'). The meteorological and theophanic vocabularies overlap intentionally.</p>",
    "16": "<p>'Do you understand how the clouds are balanced (mip̄lĕśê ʿāḇ) — the wonders of the one who is perfect in knowledge (tĕmîm dēʿôṯ)?' — mip̄lĕśê (balancing/equipoising, from p̄ālas = to weigh) applied to clouds: how are they suspended rather than falling? This was a genuine ancient puzzle — what keeps dense clouds aloft? Elihu's answer is theological: divine skill (tĕmîm dēʿôṯ, 'perfect in knowledge', the same epithet Elihu applied to himself in 36:4). The rhetorical question form anticipates ch38's relentless 'can you...? do you know...?' interrogation.</p>",
    "17": "<p>'Why your clothes are warm when the earth lies still under the south wind?' — the question about bodily warmth and the stilling of the wind during hot weather. The theological point: even something as immediate and personal as the warmth of one's clothing is connected to divine governance of the atmosphere. The south wind (dārôm) bringing heat appears in Luke 12:55 ('when you see the south wind blowing, you say it will be hot'). The mundane experience of weather on the skin is one more point in the continuum of divine care.</p>",
    "18": "<p>'Have you joined him in spreading out the sky (rāqîaʿ), firm and hard as a poured metal mirror?' — rāqaʿ (to spread out by hammering; rāqîaʿ = the firmament of Gen 1:6-8) applied to the sky as a hammered-metal surface. The 'poured metal mirror' (kĕmareʾāh mûṣāq) is a polished bronze mirror — the same technology as the bronze mirrors donated by the women at the Tabernacle (Exod 38:8). The firmament-as-mirror metaphor suggests the sky as the polished surface that reflects divine glory downward. Paul may echo this in 1 Cor 13:12 ('now we see through a mirror dimly').</p>",
    "19": "<p>'Tell us what we should say to him — we cannot arrange our words because of our darkness' — the epistemological admission of limit: human darkness (ḥōšeḵ, the same word for pre-creation chaos in Gen 1:2) prevents the right arrangement of words before God. The irony is that Elihu has been arranging extensive words to Job on God's behalf; now he acknowledges the limit of human speech before the divine. This admission is the threshold before theophany: the collapse of human language precedes the divine word.</p>",
    "20": "<p>'Should he be told that I want to speak? Can anyone speak to him without being consumed?' — the question of whether human speech registers with God at all. The consumption (yĕbullāʿ, from bālaʿ = to swallow up) is the fate of one who approaches God without proper mediation — the same concern as Exod 33:20 ('you cannot see my face, for no one can see me and live'). Elihu's rhetoric has reached its limit: the speech about God's speech has led to silence before the actual divine presence.</p>",
    "21": "<p>'And now people cannot look at the bright light (ʾôr bāhîr) in the clouds; but the wind comes and sweeps them away' — the inaccessibility of the divine light in the clouds: human eyes cannot look directly at the luminous theophanic cloud-presence. The bright light (bāhîr, = pure/clear/shining) in clouds connects to the Sinai theophany (Exod 24:16-17 'the glory of the LORD looked like consuming fire') and Ezekiel's chariot-vision (Ezek 1:4, 27-28). The wind that sweeps the obscuring clouds away prepares for the wind/whirlwind from which God will actually speak in v1 of ch38.</p>",
    "22": "<p>'From the north comes golden brightness (mizzāhāḇ yāʾāteh); God comes in fearsome majesty (nôrāʾ hôḏ)' — the golden light from the north: Ps 48:2 identifies Zion as 'beautiful in elevation, the joy of the whole earth... in the far north (yarkĕṯê ṣāp̄ôn).' The Ugaritic texts describe Baal's palace as located on the holy mountain in the north (Ṣāp̄ôn = Zaphon/the north). Elihu uses the same sacred-geography vocabulary for YHWH: the gold-brightness from the north is YHWH's own theophanic approach. hôḏ (majesty/splendor) is the divine attribute of Ps 96:6; 104:1; 1 Chron 29:11 (David's doxology).</p>",
    "23": "<p>'As for the Almighty (Šaddai), we cannot reach him (lōʾ-nimmĕṣāʾhû); he is great in power (ḵōaḥ), in justice (mišpāṭ), and in abundant righteousness (ṣĕḏāqāh)' — the triple attribute of divine greatness is the closest Elihu comes to a formal doxology. The pairing of power with justice and righteousness prevents the divine might from being raw force: it is morally structured power. This framing anticipates the divine speech, which will demonstrate power but will be implicitly just in vindicating Job. Paul draws on Job 23:3 and this language in Rom 11:33 ('the depth of the riches... of the knowledge of God; how unsearchable his judgments and his paths beyond tracing').</p>",
    "24": "<p>'Therefore people fear him; he does not attend to those who are wise in their own eyes (ḥaḵmê-lēḇ)' — the conclusion of Elihu's speech: appropriate fear of God is the human response to the incomprehensibility-and-righteousness of divine majesty. The final clause — that God does not attend to those wise in their own eyes — echoes Prov 3:7 ('do not be wise in your own eyes; fear the LORD') and functions as a subtle final critique of Job's confidence in his own case: self-assured wisdom before God is precisely the posture that forfeits divine attention. The irony is that Elihu himself has displayed this same self-assured wisdom throughout chs. 32-37.</p>"
  },
  "38": {
    "1": "<p>'Then the LORD (YHWH) answered Job out of the whirlwind (min-hassĕʿārāh)' — the first occurrence of the divine name YHWH since the prose frame (chs. 1-2). Throughout the poetic dialogue (chs. 3-37), the name used is consistently ʾĔlōah, Šaddai, or ʾĒl — the generic/archaic divine names appropriate to the patriarchal setting. The return of YHWH marks the irruption of the covenantal God into the philosophical disputation. sĕʿārāh (storm-wind/whirlwind) is the standard vehicle of theophany: 2 Kings 2:1 (Elijah's whirlwind translation); Ezek 1:4 (Ezekiel's chariot-vision from a great storm-wind); Ps 50:3 ('our God comes and will not be silent; a devouring fire precedes him and around him a tempest').</p>",
    "2": "<p>'Who is this who clouds (ḥašeḵ) my purpose (ʿĕṣāh) with words that have no knowledge (dĕʿaṯ) behind them?' — the divine opening challenge reframes the entire dialogue as an epistemic failure. ḥāšaḵ (to darken/obscure) applied to divine counsel: Job's arguments have functioned as interference, obscuring rather than illuminating God's purposeful design. ʿĕṣāh (counsel/purpose/plan) is the divine plan-word of Isa 46:10 ('my purpose will stand; I will do all that I please'); Prov 8:14 (Wisdom's self-description: 'counsel/ʿēṣāh is mine'). The charge is not that Job lied but that he spoke about matters beyond his knowledge — the epistemological critique that will structure the entire divine speech.</p>",
    "3": "<p>'Brace yourself like a man (ʾĕzor-nāʾ ḵĕḡeḇer)' — the warrior-preparation formula: gird the loins for combat. gāḇer (man/warrior/hero) is the intensive masculine, the person of strength and courage. The command is simultaneously respectful (God invites Job to stand as an equal in discourse) and ironic (no creature can actually stand as God's equal in the cross-examination that follows). 'I will question you and you must answer me' — the reversal of Job's legal wish: Job has demanded an audience (13:3; 23:3-7) and now receives it — but as respondent, not plaintiff. The roles are exchanged.</p>",
    "4": "<p>'Where were you when I laid the earth's foundation? Tell me, if you have understanding (bîn)' — the first cosmogonic question, framing all that follows: Job's absence at creation renders him epistemically incompetent to second-guess the Creator. This is not divine bullying but a genuine epistemological point: the creature cannot evaluate governance processes whose origins predate its own existence. The 'foundation of the earth' (yĕsod hāʾāreṣ) vocabulary appears in Ps 102:25 (Heb 1:10 quotes this of Christ: 'In the beginning, O Lord, you laid the foundations of the earth') and Prov 8:29 (Wisdom was present when foundations were set).</p>",
    "5": "<p>'Who determined its measurements — do you know?' — the measurement question. The earth's dimensions as set by divine measurement connects to the building and creation analogy: just as a skilled craftsman measures before building, God measured before creating. The motif appears in Isa 40:12 ('who has measured the waters in the hollow of his hand... and with a scale weighed the mountains?') — a direct parallel to this divine speech that Paul echoes in Rom 11:34. The creator's knowledge of measurement is evidence of purposive intelligent design.</p>",
    "6": "<p>'On what were its foundations set? Or who laid its cornerstone (ʾeḇen pinnāh)?' — the cornerstone (ʾeḇen pinnāh) of creation appears here for the first time in Scripture as a cosmological concept. In Ps 118:22 it becomes the rejected stone that becomes the head of the corner — Jesus applies this to himself (Matt 21:42 = Ps 118:22; 1 Pet 2:4-7 explicitly uses the 'cornerstone' language with reference to Christ). Isaiah 28:16 ('a precious cornerstone for a sure foundation') is the Messianic usage Paul quotes in Rom 9:33. The cosmological cornerstone is the semantic foundation for all subsequent cornerstone theology.</p>",
    "7": "<p>'When the morning stars (bĕnê-kôḵāḇîm) rang out together and all the divine beings (bĕnê ʾĔlōhîm) shouted for joy?' — the celestial court present at creation: the morning stars and the sons of God (the divine council of the prologue, Job 1:6; 2:1) as witnesses to the creation event. Col 1:16-17 ('all things were created through him and for him... he is before all things') places Christ at creation as the agent through whom all these beings were made; Rev 5:11-12 shows the same angelic beings singing praises — the joy at creation reversed by the Fall and restored at the Lamb's enthronement.</p>",
    "8": "<p>'Who shut in (wayyāsêḵ) the sea with doors when it burst out from the womb?' — the sea (yām) at birth: the creation of the sea is described as a controlled birthing — not the violent Chaoskampf of the Baal Cycle (where Baal fights and defeats Prince Yam) but a sovereign God who sets boundaries for a creature that 'burst out from the womb.' The domestication of the Canaanite sea-monster mythology is deliberate: YHWH did not fight the sea; he was present at its birth as the midwife/parent who then set its limits. The sea is powerful but created and bounded.</p>",
    "9": "<p>'When I made clouds its garment (lĕḇûšô) and thick darkness (ʿărāp̄el) its swaddling cloth (ḥăṯûllāṯô)' — the infant-sea dressed in cloud and darkness: the swaddling image extends the birth metaphor. ʿărāp̄el (thick/heavy darkness) is the darkness of the Sinai theophany (Exod 20:21 'Moses approached the thick darkness where God was'; Deut 4:11). The wrapping of the sea in divine theophanic darkness means its boundaries are maintained by the same divine presence that was present at Sinai — the creator's ongoing governance is covenantal governance.</p>",
    "10": "<p>'When I fixed (waʾešbōr) its boundaries (ḥuqqî) and set its bars (bĕrîaḥ) and doors (dĕlāṯayim)' — ḥōq (appointed limit/statute) applied to the sea: the same word used for legal statutes (Ps 2:7 'the decree/ḥōq of the LORD') also designates the sea's boundary. The sea has a statute: it must remain within its appointed limits. The bars and doors (bĕrîaḥ = a sliding bar across a gate; dĕlet = door) describe a fortified lock on the cosmic gate that prevents the sea from overwhelming dry land. This cosmological lock is the guarantee of creation's stability.</p>",
    "11": "<p>'When I said: This far you may come and no farther (wĕlōʾ ṯōsîp̄); here your proud waves (gaʾăwān gallêḵā) will stop' — the divine speech to the sea as a legal boundary-setting: the sea has a word spoken to it that constitutes its limit. 'Your proud waves' (gaʾăwāh = pride/majesty of waves) personifies the sea as a potentially proud being that could exceed its bounds. Psalm 46:2-3 and 65:7 use similar imagery for YHWH subduing the roaring seas and their waves; Matt 8:26-27 records Jesus stilling the storm — the disciples' amazement ('what kind of man is this?') registers that Jesus does what only YHWH does here.</p>",
    "12": "<p>'Have you ever commanded the morning since your life began, or told the dawn where to take its place?' — the daily renewal of morning as a command (ṣāwwāh = command) given by God. Job's entire life has been bounded by mornings he did not cause: every sunrise he has witnessed was a divine act he received passively. The 'place' (mĕqômô) of the dawn is its assigned position in the created order — the same vocabulary as the stars assigned their positions in Gen 1:14-18. The dawn is not autonomous but positioned by divine instruction.</p>",
    "13": "<p>'So that it would seize the earth's edges (ḵanp̄ôṯ hāʾāreṣ = the wings/corners of the land) and shake the wicked out of it?' — the morning-light as a divine shaking mechanism: like shaking a garment to remove dirt or insects, the dawn shakes (wayyinnaaărû) the wicked from their hiding places. The 'wings of the earth' (ḵānāp̄ = wing) appears in Isa 11:12 (gathering exiles from the 'four corners/wings of the earth'). The metaphor of earth as a garment that can be shaken has eschatological resonance: Heb 12:26-27 ('the shaking... of not only the earth but also the heavens').</p>",
    "14": "<p>'The earth changes like clay under a seal; its features stand out like a garment' — morning light reveals the earth's topology by producing shadows (features 'standing out' as in embossed work). The seal-and-clay metaphor is from ANE administrative practice: clay tablets or documents were authenticated by rolling a cylinder seal across wet clay, creating the raised impression. The morning sun rolling across the earth produces topographical impressions in the same way — the theological point being that creation carries the divine imprint (the creator's seal) just as a document carries the administrator's seal.</p>",
    "15": "<p>'From the wicked their light is taken away, and the arm raised in violence (zĕrôaʿ rāmāh) shall be broken' — the judicial function of the morning: the light that reveals and sustains the just is the same light that exposes and disables the violent. zĕrôaʿ rāmāh (the raised/high arm) is the image of violent force poised to strike: its 'breaking' (tiššāḇēr, niphal of šāḇar = to be shattered) is the divine interruption of injustice. Ps 10:15 uses the same prayer: 'Break the arm of the wicked and evil man'; Isa 33:1 applies this to Assyria's violent arm.</p>",
    "16": "<p>'Have you gone down to the springs of the sea (yinḇê-yām, = sources/springs of the sea) or walked through the depths of the abyss (ḥēqer tĕhôm)?' — the underwater geography beyond human reach: the springs feeding the sea from below (connected to the 'deep' of Gen 1:2 and the flood's 'fountains of the deep' in Gen 7:11). tĕhôm (the primordial deep/abyss) is the cosmic ocean of Gen 1:2 over which the Spirit hovered. The 'exploration' question makes the point that human navigation has not reached these foundations — the ocean's sources remain divinely hidden.</p>",
    "17": "<p>'Have the gates of death (šaʿărê māwet) been revealed to you? Have you seen the doors of deepest darkness (ṣalmāwet)?' — the gates of death (šĕʾôl's entry points) as a geographic reality in ANE cosmography: the underworld has gates and doors through which the dead enter. Ps 9:13 ('O LORD, see how my enemies persecute me! Have mercy and lift me up from the gates of death'); Isa 38:10 (Hezekiah: 'in the middle of my life I must enter the gates of Sheol'). Jesus's promise in Matt 16:18 ('the gates of Hades will not overcome it') draws directly on this vocabulary: he holds authority over these gates (Rev 1:18 'I hold the keys of death and Hades').</p>",
    "18": "<p>'Have you comprehended the earth's full breadth (rōḥaḇ hāʾāreṣ)? Tell me, if you know all of it' — the spatial challenge: Job has occupied a small portion of the earth (Uz) for a brief time; the earth's full extent is as unknown to him as the sea's depths. The 'full breadth' (rōḥaḇ) is the spatial analog of the temporal challenge in 36:26: just as divine years cannot be counted, divine space cannot be fully mapped. The two theological incomprehensibilities (time and space) together establish that no creature can comprehend the totality of God's domain.</p>",
    "19": "<p>'Where is the way to where light lives (šeḵen-ʾôr)? And where does darkness make its home (mĕqômô)?' — the metaphysical geography question: light and darkness have 'dwelling places' (šāḵan = to dwell/tabernacle; māqôm = place/dwelling). The personification of light and darkness as beings with domiciles (rather than mere physical phenomena) reflects the ANE cosmographic tradition in which all natural forces are personal agents. Theologically, the question establishes that YHWH knows the dwelling-places of both — the darkness is not outside divine knowledge or governance, which is the implicit answer to Job's complaints about divine absence in darkness.</p>",
    "20": "<p>'Can you take it to its territory and find the paths to its dwelling?' — the question of whether Job can navigate to the home of light or darkness: the answer is no, and the theological implication is that Job's ability to evaluate divine governance is correspondingly limited. One cannot judge the management of a house one has never entered. The paths (nĕṯîḇôṯ = narrow paths/pathways) to these primordial dwellings are only known to the One who placed them there.</p>",
    "21": "<p>'You know, of course — for you were born then, and the number of your days is very great!' — the divine sarcasm (the only moment of divine irony in the speech): Job speaks as though he has comprehensive knowledge; the ironic response is to suggest he must have been present at creation to know so much. The force is not contemptuous but rhetorically precise: the creature cannot have firsthand knowledge of what preceded its existence. The 'great number of your days' is ironic — Job's lifespan is infinitesimal compared to the duration of creation's governance.</p>",
    "22": "<p>'Have you gone into the storehouses of the snow (ʾôṣĕrôṯ šeleḡ) or have you seen the storehouses of the hail?' — the 'storehouses' (ʾôṣār = treasure-house/storeroom) of meteorological phenomena: snow and hail are stored divine resources held for appointed deployment. Elihu introduced this motif (36:27-33); now the divine speech makes it explicit. The storehouse metaphor positions God as a supply-chain manager of creation's materials. Wisdom of Solomon 16:16-17 and later apocalyptic texts (1 Enoch 17:3; 4 Ezra 4:5) develop this storehouse imagery extensively.</p>",
    "23": "<p>'Which I have kept in reserve for the time of trouble (ʿēṯ-ṣār), for the day of battle and war' — the hail as a divine weapon held in reserve for judgment: Josh 10:11 ('the LORD hurled large hailstones down on them from the sky') and Isa 28:2 (a devastating hailstorm as YHWH's instrument of judgment on Ephraim). Apocalyptically: Rev 8:7 (hail and fire mixed with blood as a plague) and Rev 16:21 ('huge hailstones, about a hundred pounds each, fell from the sky on people'). The storage of judgment-instruments anticipates their eschatological deployment.</p>",
    "24": "<p>'By what path does the light divide, or the east wind (qādîm) scatter itself across the earth?' — the east wind (qādîm = the east/the front) as a powerful dividing force: Exod 14:21 ('the LORD drove the sea back with a strong east wind all night'); Jonah 4:8 (the scorching east wind). The divine wind-governance from the east — the direction of sunrise and, theologically, the direction of divine approach — is only known to the One who sends it. No human meteorologist can predict the full path of the dividing light or the scatter of the wind.</p>",
    "25": "<p>'Who has cut a channel (pēleg) for the flood of waters, or a path for the thunderbolt (qôl hāzîz)?' — pēleg (channel/stream; from pālag = to divide) appears in Ps 1:3 ('like a tree planted by streams of water') and Ps 65:9 ('you care for the land and water it; you enrich it abundantly; the stream of God is full of water'). The theological point: the channels of rain-distribution are divinely engineered. The thunderbolt's path is not random but follows a cut channel — lightning is guided, not stochastic, in the divine economy.</p>",
    "26": "<p>'To bring rain on a land where no person lives, on the desert with no human in it' — rain on uninhabited land: the most powerful argument against a purely anthropocentric theology of providence. God sends rain where no human benefits from it — the desert receives divine irrigation regardless of human witness or need. This refutes the idea that creation exists solely for human utility. Ps 104:14-15 shows God providing for all creation; Matt 6:26-30 uses bird-and-lily language to argue from non-human divine care to human care. Both depend on this premise: God cares for what is beyond human observation.</p>",
    "27": "<p>'To satisfy (lĕhašbîaʿ) the desolate wasteland and make the tender grass spring up?' — šāḇaʿ (to be full/satisfied) used for the wasteland: even uninhabited desolation is 'satisfied' by divine provision. The theological anthropology implied is significant: divine satisfaction of creation is not defined by human presence or perception. The sprouting of tender grass (deše, the same word as Gen 1:11's 'seed-bearing plants') in uninhabited desert is a participation in the original creation-command to 'bring forth.' Creation's productivity in hidden places is itself a form of ongoing divine 'very good.'</p>",
    "28": "<p>'Does the rain have a father? Who has fathered (hôlîḏ) the drops of dew?' — the paternity question applied to precipitation: is there a generative cause for rain and dew? The answer YHWH implies is himself — but the form of the question is gendered male (father/fathering) in contrast to the mothering/womb imagery of the sea's birth in v8-9. The pairing of masculine and feminine generative metaphors for different aspects of creation suggests that neither category adequately captures the divine-creation relationship: YHWH is parent of creation in ways that exceed gender categories.</p>",
    "29": "<p>'From whose womb (meʾayîn yāṣāʾ) did the ice come? Who gave birth to the frost of heaven?' — continuing the birth-metaphor: ice and frost have divine parentage. The 'womb' of the ice (meʾayîn yāṣāʾ, lit. 'from whose belly/source did it come out') connects to the sea's womb-birth in v8 and the creation of humanity from the earth's 'womb' (Ps 139:15 'woven together in the depths of the earth'). Creation as divine birthing — with YHWH as the generative source of even inanimate natural phenomena — is the boldest theological claim of the divine speech.</p>",
    "30": "<p>'The waters harden (yitḥabbāʾû, from ḥābāʾ = to hide/conceal; or possibly from ḥāba = to harden) like stone, and the surface of the deep (tĕhôm) is locked' — water becoming ice as an act of divine 'hiding' or 'locking': the liquid surface of the primordial deep (tĕhôm, the deep of Gen 1:2) is sealed by freezing. The verb suggests something hidden — the living water is concealed beneath the frozen surface. Theologically: even the face of the primordial deep, the chaos-water of creation, is subject to divine governance that can immobilize and conceal it.</p>",
    "31": "<p>'Can you bind (qāšar) the chains (maʿdānôṯ) of the Pleiades (Kîmāh), or can you release (pittaḥ) the belt of Orion (Kĕsîl)?' — the constellation-governance question: Kîmāh (Pleiades, the cluster; from kūm = to be firm/thick?) and Kĕsîl (Orion, literally 'the fool/self-confident one'). Both appear in Job 9:9 and Amos 5:8 ('he who made the Pleiades and Orion'). The Pleiades' 'chains' and Orion's 'belt' are anthropomorphized features of star-clusters: their apparent fixed patterns across seasons are described as divine binding (chains cannot be loosened; belt cannot be tightened). Only God can alter the constellations' courses.</p>",
    "32": "<p>'Can you bring out Mazzaroth (mazzārôṯ) in its season? Can you guide the Bear (ʿAyiš) with its cubs?' — mazzārôṯ (the zodiac constellations? the morning star? uncertain) appearing only here; the LXX translates as Μαζουρωθ; likely the twelve signs of the zodiac or a subset. ʿAyiš (the Bear/Ursa Major, lit. 'the bearess/she-bear') with its cubs (the bright stars of the dipper handle). The seasonal bringing-out of constellations (each visible at its proper time) is framed as divine guidance: God knows and controls the cosmic calendar in ways no human astronomer can replicate.</p>",
    "33": "<p>'Do you know the laws of heaven (ḥuqqôṯ šāmayim)? Can you establish its rule (mišṭār) over the earth?' — ḥuqqôṯ (statutes/laws) of heaven: the same legal vocabulary used for covenant statutes (Torah/ḥuqqîm) is applied to the governing rules of the astronomical system. The cosmos operates by divine statutes; it is not governed by impersonal natural laws but by the same divine legislative authority that issued the Sinai covenant. mišṭār (dominion/rule) of heaven over earth: the celestial realm governs the terrestrial — a conception that will develop through Danielic apocalypticism into the NT framework of heavenly and earthly realms.</p>",
    "34": "<p>'Can you raise your voice to the clouds and make a flood of water come down?' — the voice-to-cloud comparison: Elihu has described God doing exactly this (37:4-5). Now God asks whether Job can do the same. The answer is no — but the form of the question also recalls Moses striking the rock (Num 20:8-11) and Elijah's prayer for rain (1 Kings 18:41-45; James 5:17-18 'Elijah was a human being... he prayed earnestly that it would not rain... he prayed again and the heavens gave rain'). Prayer as a form of 'raising the voice to the clouds' is a genuine human power — but only under divine authorization.</p>",
    "35": "<p>'Can you send out lightning bolts (bĕrāqîm) on commission (tiślāḥēm), and do they report back to you: Here we are?' — the lightning-as-messenger image: YHWH dispatches lightning as a divine emissary; the 'here we are' (hinnennû, the response of a servant reporting for duty) personifies the lightning bolts as obedient messengers. The same formula 'here I am' (hinĕnî) is the response of the faithful servant to the divine call: Abraham (Gen 22:1), Moses (Exod 3:4), Isaiah (6:8). The lightning obeys and reports; Job cannot command such messengers.</p>",
    "36": "<p>'Who has placed wisdom (ḥoḵmāh) within the hidden self (ṭuḥôṯ, = inner parts/kidneys)?' — ṭuḥôṯ (the inward parts, often translated 'inmost being') as the location of implanted wisdom: this is the 'inner man' of Ps 51:6 ('you desire truth in the inmost being/ṭuḥôṯ; you teach me wisdom in the inmost place') and Jer 31:33 ('I will put my law in their minds and write it on their hearts'). The wisdom given internally connects to 1 Cor 2:10 ('the Spirit searches all things, even the deep things of God'), which Paul develops as the New Covenant fulfillment of this interior divine gift.</p>",
    "37": "<p>'Who has the wisdom to count the clouds? Who can tilt (yašqîp̄ = incline/tip) the water jars of heaven?' — the cloud-counting wisdom returns: Elihu raised it (37:16); now God claims it. The 'water jars of heaven' (nibleê šāmayim = waterskins/bottles of heaven) is a different meteorological image from 36:27's distillation — here the clouds are waterskins that God tips to pour out rain. The two images together (distillation from below, pouring from above) capture both aspects of the hydrological cycle. Only divine wisdom knows how much water is in the sky and when to tip it.</p>",
    "38": "<p>'When the dust hardens into a mass and the clods of dirt cling together?' — the agricultural context of rain timing: rain at the right moment softens hard ground (enabling plowing and planting); too much rain turns soil to mud; too little leaves it hard as baked clay. The dust hardening and clods clinging is the condition of drought-parched soil or post-harvest fields. God's wisdom in timing the rain precisely is the point: the difference between a productive and unproductive agricultural year depends on timing that lies entirely outside human control.</p>",
    "39": "<p>'Do you hunt prey (ṭerepā) for the lion (layyiš, = an old/mature lion) and fill the hunger (ḥayyāh, = life/appetite) of its cubs?' — the shift from inanimate creation to animal care: God as provider for the top predator. layyiš (the older, experienced lion; Job 4:11 same word) is distinguished from ʾarî (the young lion). The lion's hunting success depends on divine provision of prey — the predator/prey relationship is embedded in divine governance. This frames ch38-39's animal survey as a theology of non-human life: God attends to the lion's hunger before asking whether Job can do the same.</p>",
    "40": "<p>'When they crouch in their dens and wait in ambush in their thickets?' — the lion's behavioral patterns (denning and ambush hunting) as divinely sustained activities. The word for 'dens' (maʿônôṯ, from ʿāwōn = to dwell) connects to the divine 'dwelling' vocabulary: God's maʿôn (habitation, Ps 90:1 'Lord, you have been our dwelling place'; Deut 33:27 'the eternal God is your refuge/maʿôn'). The lion's den and the divine dwelling use the same word — subtly suggesting that the wild places where lions live are also places where God dwells, not zones of divine absence.</p>",
    "41": "<p>'Who provides the raven (ʿōrēḇ) its food when its chicks cry out to God and wander about hungry?' — the final verse of ch38 is the raven: among the most ambivalent birds in the OT (Gen 8:7, the first bird sent from the ark; Lev 11:15, unclean; 1 Kings 17:4-6 the ravens that fed Elijah). The raven's chicks 'crying out to God' (yĕšawwĕʿû ʾel-ʾēl) places even the raven's hunger prayer within the sphere of divine response. Ps 147:9 ('he feeds the ravens when they call'); Luke 12:24 ('consider the ravens... God feeds them'). Jesus's encouragement to human trust in divine provision rests on this premise: if God hears the raven, he hears you.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'job')
    merge_comm(c, JOB3638)
    save_comm('mkt-context', 'job', c)
    count = sum(len(v) for v in JOB3638.values())
    print(f'job mkt-context: wrote {count} verses for ch 36–38')

if __name__ == '__main__':
    main()
